#!/usr/bin/env python3
from pwn import *
import re

p=14753
a=1
b=-1
n=7919
G=(1,1)

def inv_mod(nv,p):
    return pow(nv,p-2,p)

def is_on(P):
    if P is None: return True
    x,y=P
    return (y*y - x*x*x - a*x - b) % p == 0

def add(P,Q):
    if P is None: return Q
    if Q is None: return P
    x1,y1=P; x2,y2=Q
    if x1==x2 and y1!=y2:
        return None
    if x1==x2:
        m=((3*x1*x1+a)*inv_mod((2*y1)%p,p))%p
    else:
        m=((y1-y2)*inv_mod((x1-x2)%p,p))%p
    x3=(m*m-x1-x2)%p
    y3=(- (y1 + m*(x3-x1)))%p
    return (x3,y3)

def mult(k,P):
    if k % n == 0 or P is None:
        return None
    if k<0:
        return neg(mult(-k,P))
    R=None
    A=P
    while k:
        if k&1:
            R=add(R,A)
        A=add(A,A)
        k >>= 1
    return R

def neg(P):
    if P is None: return None
    x,y=P
    return (x,(-y)%p)

def solve_dlog_bruteforce(Q):
    R=None
    for k in range(n):
        if R==Q:
            return k
        R=add(R,G)
    return None

io=remote('crypto.chal.csaw.io',8000)
text=io.recvuntil(b'What is the secret?').decode()
print(text)
m=re.search(r'Public key: \((\d+), (\d+)\)',text)
if not m:
    raise SystemExit('No pub parsed')
Q=(int(m.group(1)),int(m.group(2)))
print('Q=',Q)
k=solve_dlog_bruteforce(Q)
print('k=',k)
io.sendlineafter(b'Asking for secret',str(k).encode())
print(io.recvall(timeout=2).decode(errors='ignore'))
